package tn.esprit.services;

import javax.speech.Central;
import javax.speech.synthesis.Synthesizer;
import javax.speech.synthesis.SynthesizerModeDesc;
import java.util.Locale;

public class TextToSpeechService {

    private Synthesizer synthesizer;
    private boolean initialized = false;

    public TextToSpeechService() {
        try {
            initializeSynthesizer();
        } catch (Exception e) {
            System.out.println("⚠️ TTS non disponible: " + e.getMessage());
        }
    }

    private void initializeSynthesizer() throws Exception {
        if (synthesizer != null) return;

        try {
            // Essayer d'utiliser le synthesizer JSAPI
            String synthesizerName = "com.sun.speech.freetts.en.us.CMUDictBasedTokenizer";

            // Chercher les providers disponibles
            String[] providers = javax.speech.Central.getEngineListByName("Synthesizer");
            if (providers != null && providers.length > 0) {
                System.out.println("✓ Providers TTS disponibles");
            }

            // Utiliser le mode par défaut
            SynthesizerModeDesc desc = new SynthesizerModeDesc(
                    null,               // Engine name
                    "general",          // Mode
                    Locale.FRANCE,      // Locale
                    Boolean.FALSE,      // Running
                    null                // Features
            );

            synthesizer = Central.createSynthesizer(desc);
            if (synthesizer != null) {
                synthesizer.allocate();
                synthesizer.resume();
                initialized = true;
                System.out.println("✓ TTS (Text-To-Speech) initialisé avec succès");
            }
        } catch (Exception e) {
            // Fallback si JSAPI n'est pas disponible
            System.out.println("⚠️ JSAPI TTS non disponible, utilisation du système");
            usePlatformTTS();
        }
    }

    private void usePlatformTTS() {
        try {
            // Windows : utiliser SAPI (Speech API)
            if (System.getProperty("os.name").toLowerCase().contains("win")) {
                initialized = true;
                System.out.println("✓ Utilisation de SAPI Windows pour TTS");
            }
        } catch (Exception e) {
            System.out.println("⚠️ TTS système non disponible");
        }
    }

    public void parler(String texte) {
        if (texte == null || texte.isBlank()) return;

        System.out.println(" LECTURE VOCALE : " + texte);

        if (synthesizer != null && initialized) {
            try {
                synthesizer.speakPlainText(texte, null);
                synthesizer.waitEngineState(Synthesizer.QUEUE_EMPTY);
            } catch (Exception e) {
                System.out.println("⚠️ Erreur lecture TTS: " + e.getMessage());
                speakUsingWindowsAPI(texte);
            }
        } else {
            // Fallback : utiliser PowerShell sous Windows
            speakUsingWindowsAPI(texte);
        }
    }

    private void speakUsingWindowsAPI(String texte) {
        try {
            // Utiliser l'API Windows native via PowerShell
            String[] cmd = {
                    "powershell.exe",
                    "-Command",
                    "(New-Object -ComObject SAPI.SpVoice).Speak(\"" + texte.replace("\"", "\\\"") + "\")"
            };

            ProcessBuilder pb = new ProcessBuilder(cmd);
            pb.redirectErrorStream(true);
            Process p = pb.start();
            p.waitFor();

            System.out.println("✓ Son Windows API joué");
        } catch (Exception e) {
            System.out.println("⚠️ Impossible de lire le texte: " + e.getMessage());
        }
    }

    public void arreter() {
        if (synthesizer != null) {
            try {
                synthesizer.deallocate();
            } catch (Exception e) {
                System.out.println("Erreur arrêt TTS: " + e.getMessage());
            }
        }
    }
}

package tn.esprit.services;

public class TextToSpeechService {

    private boolean initialized = false;

    public TextToSpeechService() {
        try {
            // Vérifier que nous sommes sur Windows
            if (System.getProperty("os.name").toLowerCase().contains("win")) {
                initialized = true;
                System.out.println("✓ TTS (Text-To-Speech) initialisé avec succès - SAPI Windows");
            } else {
                System.out.println("⚠️ TTS: Système non-Windows détecté. Synthèse vocale limitée.");
            }
        } catch (Exception e) {
            System.out.println("⚠️ TTS non disponible: " + e.getMessage());
        }
    }

    public void parler(String texte) {
        if (texte == null || texte.isBlank()) return;

        System.out.println(" LECTURE VOCALE : " + texte);

        if (synthesizer != null && initialized) {
            try {
                synthesizer.speakPlainText(texte, null);
                synthesizer.waitEngineState(Synthesizer.QUEUE_EMPTY);
            } catch (Exception e) {
                System.out.println("⚠️ Erreur lecture TTS: " + e.getMessage());
                speakUsingWindowsAPI(texte);
            }
        } else {
            // Fallback : utiliser PowerShell sous Windows
            speakUsingWindowsAPI(texte);
        }
    }

    private void speakUsingWindowsAPI(String texte) {
        try {
            // Utiliser l'API Windows native via PowerShell
            String[] cmd = {
                    "powershell.exe",
                    "-Command",
                    "(New-Object -ComObject SAPI.SpVoice).Speak(\"" + texte.replace("\"", "\\\"") + "\")"
            };

            ProcessBuilder pb = new ProcessBuilder(cmd);
            pb.redirectErrorStream(true);
            Process p = pb.start();
            p.waitFor();

            System.out.println("✓ Son Windows API joué");
        } catch (Exception e) {
            System.out.println("⚠️ Impossible de lire le texte: " + e.getMessage());
        }
    }

    public void arreter() {
        if (synthesizer != null) {
            try {
                synthesizer.deallocate();
            } catch (Exception e) {
                System.out.println("Erreur arrêt TTS: " + e.getMessage());
            }
        }
    }
}
